  1в†’import {
  2в†’  type Conversation,
  3в†’  conversationSchema,
  4в†’  type ImportStage,
  5в†’  type NormalizedSnapshotPayload,
  6в†’  normalizedSnapshotPayloadSchema,
  7в†’} from "@chat-exporter/shared";
  8в†’import { acquireContext, releaseContext } from "./browser-pool.js";
  9в†’import { MAX_MESSAGE_COUNT, MAX_RAW_HTML_BYTES } from "./constants.js";
 10в†’import { applyOpenAiStructuring } from "./openai-structuring.js";
 11в†’
 12в†’/* в”Ђв”Ђ ChatGPT share-import constants в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */
 13в†’
 14в†’/** Timeout for the initial page.goto() navigation. */
 15в†’export const PAGE_LOAD_TIMEOUT_MS = 30_000;
 16в†’
 17в†’/** Timeout for waiting until message elements appear in the DOM. */
 18в†’export const MESSAGE_WAIT_TIMEOUT_MS = 20_000;
 19в†’
 20в†’/** Extra delay after messages appear to let the page stabilize. */
 21в†’export const PAGE_STABILIZATION_MS = 800;
 22в†’
 23в†’/** CSS selector that identifies ChatGPT share-page message elements. */
 24в†’export const CHATGPT_SHARE_SELECTOR = "article [data-message-author-role]";
 25в†’
 26в†’/* в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */
 27в†’
 28в†’type StageCallback = (
 29в†’  stage: Extract<ImportStage, "fetch" | "extract" | "normalize" | "structure">,
 30в†’) => void;
 31в†’
 32в†’type ImportResult = {
 33в†’  conversation: Conversation;
 34в†’  warnings: string[];
 35в†’  snapshot: {
 36в†’    finalUrl: string;
 37в†’    fetchedAt: string;
 38в†’    pageTitle: string;
 39в†’    rawHtml: string;
 40в†’    normalizedPayload: NormalizedSnapshotPayload;
 41в†’    fetchMetadata: {
 42в†’      articleCount: number;
 43в†’      messageCount: number;
 44в†’      rawHtmlBytes: number;
 45в†’    };
 46в†’  };
 47в†’};
 48в†’
 49в†’export async function importChatGptSharePage(
 50в†’  url: string,
 51в†’  options?: {
 52в†’    onStage?: StageCallback;
 53в†’  },
 54в†’): Promise<ImportResult> {
 55в†’  const context = await acquireContext();
 56в†’
 57в†’  try {
 58в†’    await context.route("**/*", (route) => {
 59в†’      const resourceType = route.request().resourceType();
 60в†’
 61в†’      if (
 62в†’        resourceType === "image" ||
 63в†’        resourceType === "media" ||
 64в†’        resourceType === "font"
 65в†’      ) {
 66в†’        return route.abort();
 67в†’      }
 68в†’
 69в†’      return route.continue();
 70в†’    });
 71в†’
 72в†’    const page = await context.newPage();
 73в†’    await page.addInitScript({
 74в†’      content: "globalThis.__name = (value) => value;",
 75в†’    });
 76в†’
 77в†’    options?.onStage?.("fetch");
 78в†’    await page.goto(url, {
 79в†’      waitUntil: "domcontentloaded",
 80в†’      timeout: PAGE_LOAD_TIMEOUT_MS,
 81в†’    });
 82в†’    await page.waitForFunction(
 83в†’      (selector) => document.querySelectorAll(selector).length > 0,
 84в†’      CHATGPT_SHARE_SELECTOR,
 85в†’      {
 86в†’        timeout: MESSAGE_WAIT_TIMEOUT_MS,
 87в†’      },
 88в†’    );
 89в†’    await page.waitForTimeout(PAGE_STABILIZATION_MS);
 90в†’
 91в†’    options?.onStage?.("extract");
 92в†’    const extracted = await page.evaluate(() => {
 93в†’      const __name = <T>(value: T) => value;
 94в†’      const wrapperTags = new Set([
 95в†’        "ARTICLE",
 96в†’        "SECTION",
 97в†’        "DIV",
 98в†’        "SPAN",
 99в†’        "FIGURE",
100в†’        "MAIN",
101в†’      ]);
102в†’      const blockTags = new Set([
103в†’        "P",
104в†’        "H1",
105в†’        "H2",
106в†’        "H3",
107в†’        "H4",
108в†’        "H5",
109в†’        "H6",
110в†’        "UL",
111в†’        "OL",
112в†’        "PRE",
113в†’        "BLOCKQUOTE",
114в†’        "TABLE",
115в†’        "HR",
116в†’      ]);
117в†’      const codeLanguageLabels = new Set([
118в†’        "plain text",
119в†’        "text",
120в†’        "json",
121в†’        "javascript",
122в†’        "typescript",
123в†’        "ts",
124в†’        "js",
125в†’        "python",
126в†’        "bash",
127в†’        "shell",
128в†’        "sql",
129в†’        "html",
130в†’        "css",
131в†’        "markdown",
132в†’        "md",
133в†’        "yaml",
134в†’        "yml",
135в†’      ]);
136в†’
137в†’      function normalizeWhitespace(value: string) {
138в†’        return value
139в†’          .replace(/\u00a0/g, " ")
140в†’          .replace(/\r/g, "")
141в†’          .replace(/[ \t\f\v]+/g, " ")
142в†’          .replace(/ *\n */g, "\n")
143в†’          .replace(/\n{3,}/g, "\n\n")
144в†’          .trim();
145в†’      }
146в†’
147в†’      function inlineText(node: Node): string {
148в†’        if (node.nodeType === Node.TEXT_NODE) {
149в†’          return node.textContent ?? "";
150в†’        }
151в†’
152в†’        if (node.nodeType !== Node.ELEMENT_NODE) {
153в†’          return "";
154в†’        }
155в†’
156в†’        const element = node as HTMLElement;
157в†’        const tagName = element.tagName.toUpperCase();
158в†’
159в†’        if (
160в†’          tagName === "BUTTON" ||
161в†’          tagName === "SVG" ||
162в†’          tagName === "PATH" ||
163в†’          tagName === "USE" ||
164в†’          tagName === "IMG" ||
165в†’          tagName === "NOSCRIPT"
166в†’        ) {
167в†’          return "";
168в†’        }
169в†’
170в†’        if (tagName === "BR") {
171в†’          return "\n";
172в†’        }
173в†’
174в†’        const childText = Array.from(element.childNodes)
175в†’          .map(inlineText)
176в†’          .join("");
177в†’
178в†’        switch (tagName) {
179в†’          case "A": {
180в†’            const text = normalizeWhitespace(childText);
181в†’            const href = element.getAttribute("href");
182в†’            return href && text ? `[${text}](${href})` : text;
183в†’          }
184в†’          case "STRONG":
185в†’          case "B": {
186в†’            const text = normalizeWhitespace(childText);
187в†’            return text ? `**${text}**` : "";
188в†’          }
189в†’          case "EM":
190в†’          case "I": {
191в†’            const text = normalizeWhitespace(childText);
192в†’            return text ? `*${text}*` : "";
193в†’          }
194в†’          case "CODE": {
195в†’            if (element.closest("pre")) {
196в†’              return "";
197в†’            }
198в†’
199в†’            const text = normalizeWhitespace(childText);
200в†’            return text ? `\`${text}\`` : "";
201в†’          }
202в†’          case "DEL":
203в†’          case "S": {
204в†’            const text = normalizeWhitespace(childText);
205в†’            return text ? `~~${text}~~` : "";
206в†’          }
207в†’          default:
208в†’            return childText;
209в†’        }
210в†’      }
211в†’
212в†’      function inlineFromElement(element: Element) {
213в†’        return normalizeWhitespace(
214в†’          Array.from(element.childNodes).map(inlineText).join(""),
215в†’        );
216в†’      }
217в†’
218в†’      function extractListItems(listElement: Element, depth = 0): string[] {
219в†’        const items: string[] = [];
220в†’        const listItems = Array.from(listElement.children).filter(
221в†’          (child) => child.tagName === "LI",
222в†’        );
223в†’
224в†’        for (const listItem of listItems) {
225в†’          let ownText = "";
226в†’
227в†’          for (const childNode of Array.from(listItem.childNodes)) {
228в†’            if (
229в†’              childNode.nodeType === Node.ELEMENT_NODE &&
230в†’              ["UL", "OL"].includes((childNode as Element).tagName)
231в†’            ) {
232в†’              continue;
233в†’            }
234в†’
235в†’            ownText += inlineText(childNode);
236в†’          }
237в†’
238в†’          const normalized = normalizeWhitespace(ownText);
239в†’          if (normalized) {
240в†’            items.push(`${"  ".repeat(depth)}${normalized}`);
241в†’          }
242в†’
243в†’          const nestedLists = Array.from(listItem.children).filter((child) =>
244в†’            ["UL", "OL"].includes(child.tagName),
245в†’          );
246в†’
247в†’          for (const nestedList of nestedLists) {
248в†’            items.push(...extractListItems(nestedList, depth + 1));
249в†’          }
250в†’        }
251в†’
252в†’        return items;
253в†’      }
254в†’
255в†’      function detectCodeLanguage(preElement: HTMLElement) {
256в†’        const firstLine =
257в†’          preElement.innerText.split("\n")[0]?.trim().toLowerCase() ?? "";
258в†’
259в†’        if (codeLanguageLabels.has(firstLine)) {
260в†’          return firstLine === "plain text" ? "text" : firstLine;
261в†’        }
262в†’
263в†’        const classHint = Array.from(preElement.querySelectorAll("[class]"))
264в†’          .map((element) => element.className)
265в†’          .join(" ");
266в†’        const languageMatch = classHint.match(/language-([a-z0-9#+-]+)/i);
267в†’        return languageMatch?.[1]?.toLowerCase() ?? "text";
268в†’      }
269в†’
270в†’      function extractCodeText(preElement: HTMLElement) {
271в†’        const lines = preElement.innerText.replace(/\r/g, "").split("\n");
272в†’
273в†’        while (lines.length > 1) {
274в†’          const firstLine = lines[0]?.trim().toLowerCase() ?? "";
275в†’          if (
276в†’            !codeLanguageLabels.has(firstLine) &&
277в†’            firstLine !== "kopieren" &&
278в†’            firstLine !== "copy"
279в†’          ) {
280в†’            break;
281в†’          }
282в†’          lines.shift();
283в†’        }
284в†’
285в†’        return lines.join("\n").trim();
286в†’      }
287в†’
288в†’      function extractTable(tableElement: HTMLTableElement) {
289в†’        const headerRows = Array.from(
290в†’          tableElement.querySelectorAll("thead tr"),
291в†’        );
292в†’        const bodyRows = Array.from(tableElement.querySelectorAll("tbody tr"));
293в†’        const fallbackRows = Array.from(tableElement.querySelectorAll("tr"));
294в†’        const firstHeaderRow = headerRows[0];
295в†’
296в†’        const headers = firstHeaderRow
297в†’          ? Array.from(firstHeaderRow.querySelectorAll("th,td")).map((cell) =>
298в†’              inlineFromElement(cell),
299в†’            )
300в†’          : [];
301в†’
302в†’        const rowSource =
303в†’          bodyRows.length > 0
304в†’            ? bodyRows
305в†’            : fallbackRows.slice(headers.length > 0 ? 1 : 0);
306в†’        const rows = rowSource
307в†’          .map((row) =>
308в†’            Array.from(row.querySelectorAll("th,td")).map((cell) =>
309в†’              inlineFromElement(cell),
310в†’            ),
311в†’          )
312в†’          .filter((row) => row.some(Boolean));
313в†’
314в†’        if (headers.length === 0 && rows.length === 0) {
315в†’          return null;
316в†’        }
317в†’
318в†’        return {
319в†’          type: "table" as const,
320в†’          headers,
321в†’          rows,
322в†’        };
323в†’      }
324в†’
325в†’      function elementToBlocks(
326в†’        element: Element,
327в†’      ): Array<Record<string, unknown>> {
328в†’        const tagName = element.tagName.toUpperCase();
329в†’
330в†’        if (tagName === "P") {
331в†’          const text = inlineFromElement(element);
332в†’          return text ? [{ type: "paragraph", text }] : [];
333в†’        }
334в†’
335в†’        if (/^H[1-6]$/.test(tagName)) {
336в†’          const text = inlineFromElement(element);
337в†’          const level = Number(tagName.slice(1));
338в†’          return text ? [{ type: "heading", level, text }] : [];
339в†’        }
340в†’
341в†’        if (tagName === "UL" || tagName === "OL") {
342в†’          const items = extractListItems(element);
343в†’          return items.length > 0
344в†’            ? [
345в†’                {
346в†’                  type: "list",
347в†’                  ordered: tagName === "OL",
348в†’                  items,
349в†’                },
350в†’              ]
351в†’            : [];
352в†’        }
353в†’
354в†’        if (tagName === "PRE") {
355в†’          const text = extractCodeText(element as HTMLElement);
356в†’          return text
357в†’            ? [
358в†’                {
359в†’                  type: "code",
360в†’                  language: detectCodeLanguage(element as HTMLElement),
361в†’                  text,
362в†’                },
363в†’              ]
364в†’            : [];
365в†’        }
366в†’
367в†’        if (tagName === "BLOCKQUOTE") {
368в†’          const text = inlineFromElement(element);
369в†’          return text ? [{ type: "quote", text }] : [];
370в†’        }
371в†’
372в†’        if (tagName === "TABLE") {
373в†’          const table = extractTable(element as HTMLTableElement);
374в†’          return table ? [table] : [];
375в†’        }
376в†’
377в†’        if (tagName === "HR") {
378в†’          return [];
379в†’        }
380в†’
381в†’        if (wrapperTags.has(tagName)) {
382в†’          const childBlocks = Array.from(element.childNodes).flatMap(
383в†’            (childNode) => {
384в†’              if (childNode.nodeType === Node.TEXT_NODE) {
385в†’                const text = normalizeWhitespace(childNode.textContent ?? "");
386в†’                return text ? [{ type: "paragraph" as const, text }] : [];
387в†’              }
388в†’
389в†’              if (childNode.nodeType !== Node.ELEMENT_NODE) {
390в†’                return [];
391в†’              }
392в†’
393в†’              return elementToBlocks(childNode as Element);
394в†’            },
395в†’          );
396в†’
397в†’          if (childBlocks.length > 0) {
398в†’            return childBlocks;
399в†’          }
400в†’        }
401в†’
402в†’        const hasBlockChildren = Array.from(element.children).some((child) =>
403в†’          blockTags.has(child.tagName),
404в†’        );
405в†’
406в†’        if (hasBlockChildren) {
407в†’          return Array.from(element.children).flatMap((child) =>
408в†’            elementToBlocks(child),
409в†’          );
410в†’        }
411в†’
412в†’        const text = inlineFromElement(element);
413в†’        return text ? [{ type: "paragraph", text }] : [];
414в†’      }
415в†’
416в†’      function normalizeTitle(rawTitle: string) {
417в†’        const title = rawTitle.replace(/^ChatGPT\s*-\s*/i, "").trim();
418в†’        return title || "Untitled Chat";
419в†’      }
420в†’
421в†’      const warnings: string[] = [];
422в†’      const articles = Array.from(document.querySelectorAll("article"));
423в†’      let fallbackCount = 0;
424в†’
425в†’      const messages = articles
426в†’        .map((article) => {
427в†’          const messageElement = article.querySelector(
428в†’            "[data-message-author-role]",
429в†’          ) as HTMLElement | null;
430в†’          if (!messageElement) {
431в†’            return null;
432в†’          }
433в†’
434в†’          const role =
435в†’            messageElement.getAttribute("data-message-author-role") ??
436в†’            "unknown";
437в†’          const messageId =
438в†’            messageElement.getAttribute("data-message-id") ??
439в†’            crypto.randomUUID();
440в†’
441в†’          if (role === "assistant") {
442в†’            const markdownRoot =
443в†’              (messageElement.querySelector(
444в†’                ".markdown",
445в†’              ) as HTMLElement | null) ?? messageElement;
446в†’            const blocks = Array.from(markdownRoot.childNodes).flatMap(
447в†’              (childNode) => {
448в†’                if (childNode.nodeType === Node.TEXT_NODE) {
449в†’                  const text = normalizeWhitespace(childNode.textContent ?? "");
450в†’                  return text ? [{ type: "paragraph" as const, text }] : [];
451в†’                }
452в†’
453в†’                if (childNode.nodeType !== Node.ELEMENT_NODE) {
454в†’                  return [];
455в†’                }
456в†’
457в†’                return elementToBlocks(childNode as Element);
458в†’              },
459в†’            );
460в†’
461в†’            const rawText = normalizeWhitespace(messageElement.innerText);
462в†’            const rawHtml = messageElement.innerHTML;
463в†’
464в†’            if (blocks.length === 0) {
465в†’              fallbackCount += 1;
466в†’              return rawText
467в†’                ? {
468в†’                    id: messageId,
469в†’                    role,
470в†’                    rawText,
471в†’                    rawHtml,
472в†’                    blocks: [{ type: "paragraph" as const, text: rawText }],
473в†’                    parser: {
474в†’                      source: "assistant-fallback",
475в†’                      blockCount: 1,
476в†’                      usedFallback: true,
477в†’                      strategy: "fallback" as const,
478в†’                    },
479в†’                  }
480в†’                : null;
481в†’            }
482в†’
483в†’            return {
484в†’              id: messageId,
485в†’              role,
486в†’              rawText,
487в†’              rawHtml,
488в†’              blocks,
489в†’              parser: {
490в†’                source: "assistant-markdown",
491в†’                blockCount: blocks.length,
492в†’                usedFallback: false,
493в†’                strategy: "deterministic" as const,
494в†’              },
495в†’            };
496в†’          }
497в†’
498в†’          const textSource =
499в†’            (messageElement.querySelector(
500в†’              ".whitespace-pre-wrap",
501в†’            ) as HTMLElement | null) ?? messageElement;
502в†’          const text = normalizeWhitespace(textSource.innerText);
503в†’          const rawHtml = textSource.innerHTML;
504в†’
505в†’          return text
506в†’            ? {
507в†’                id: messageId,
508в†’                role,
509в†’                rawText: text,
510в†’                rawHtml,
511в†’                blocks: [{ type: "paragraph" as const, text }],
512в†’                parser: {
513в†’                  source:
514в†’                    textSource === messageElement
515в†’                      ? "user-message"
516в†’                      : "user-whitespace-pre-wrap",
517в†’                  blockCount: 1,
518в†’                  usedFallback: false,
519в†’                  strategy: "deterministic" as const,
520в†’                },
521в†’              }
522в†’            : null;
523в†’        })
524в†’        .filter(Boolean);
525в†’
526в†’      if (fallbackCount > 0) {
527в†’        warnings.push(
528в†’          `${fallbackCount} assistant message(s) fell back to a plain paragraph because no richer block structure was detected.`,
529в†’        );
530в†’      }
531в†’
532в†’      return {
533в†’        title: normalizeTitle(document.title),
534в†’        messages,
535в†’        warnings,
536в†’      };
537в†’    });
538в†’
539в†’    options?.onStage?.("normalize");
540в†’    const normalizedPayload = normalizedSnapshotPayloadSchema.parse(extracted);
541в†’
542в†’    if (normalizedPayload.messages.length > MAX_MESSAGE_COUNT) {
543в†’      const originalCount = normalizedPayload.messages.length;
544в†’      normalizedPayload.messages = normalizedPayload.messages.slice(
545в†’        -MAX_MESSAGE_COUNT,
546в†’      );
547в†’      normalizedPayload.warnings.push(
548в†’        `Nachrichtenlimit Гјberschritten: ${originalCount} Nachrichten gefunden, auf die letzten ${MAX_MESSAGE_COUNT} gekГјrzt.`,
549в†’      );
550в†’    }
551в†’
552в†’    options?.onStage?.("structure");
553в†’    const structured = await applyOpenAiStructuring(normalizedPayload.messages);
554в†’    const finalPayload = normalizedSnapshotPayloadSchema.parse({
555в†’      ...normalizedPayload,
556в†’      messages: structured.messages,
557в†’      warnings: [...normalizedPayload.warnings, ...structured.warnings],
558в†’      structuring: structured.structuring,
559в†’    });
560в†’    const rawHtml = await page.content();
561в†’    const rawHtmlBytes = Buffer.byteLength(rawHtml, "utf8");
562в†’    if (rawHtmlBytes > MAX_RAW_HTML_BYTES) {
563в†’      const sizeMb = (rawHtmlBytes / (1024 * 1024)).toFixed(1);
564в†’      const limitMb = (MAX_RAW_HTML_BYTES / (1024 * 1024)).toFixed(1);
565в†’      throw new Error(
566в†’        `HTML-GrГ¶Гџe Гјberschritten: ${sizeMb} MB (Limit: ${limitMb} MB).`,
567в†’      );
568в†’    }
569в†’    const fetchedAt = new Date().toISOString();
570в†’
571в†’    const conversation = conversationSchema.parse({
572в†’      id: crypto.randomUUID(),
573в†’      title: finalPayload.title,
574в†’      source: {
575в†’        url,
576в†’        platform: "chatgpt",
577в†’      },
578в†’      messages: finalPayload.messages,
579в†’    });
580в†’
581в†’    return {
582в†’      conversation,
583в†’      warnings: finalPayload.warnings,
584в†’      snapshot: {
585в†’        finalUrl: page.url(),
586в†’        fetchedAt,
587в†’        pageTitle: finalPayload.title,
588в†’        rawHtml,
589в†’        normalizedPayload: finalPayload,
590в†’        fetchMetadata: {
591в†’          articleCount: normalizedPayload.messages.length,
592в†’          messageCount: conversation.messages.length,
593в†’          rawHtmlBytes: Buffer.byteLength(rawHtml, "utf8"),
594в†’        },
595в†’      },
596в†’    };
597в†’  } finally {
598в†’    await releaseContext(context);
599в†’  }
600в†’}
