12в†’export function classifySourcePlatform(urlString: string): SourcePlatform {
13в†’  const url = new URL(urlString);
14в†’  const hostname = normalizeHostname(url.hostname);
15в†’  const pathname = url.pathname.toLowerCase();
16в†’
17в†’  if (
18в†’    hostname === "chatgpt.com" ||
19в†’    hostname.endsWith(".chatgpt.com") ||
20в†’    hostname === "chat.openai.com"
21в†’  ) {
22в†’    return "chatgpt";
23в†’  }
24в†’
25в†’  if (hostname === "claude.ai" || hostname.endsWith(".claude.ai")) {
26в†’    return "claude";
27в†’  }
28в†’
29в†’  if (
30в†’    hostname === "gemini.google.com" ||
31в†’    hostname.endsWith(".gemini.google.com") ||
32в†’    (hostname === "g.co" && pathname.startsWith("/gemini"))
33в†’  ) {
34в†’    return "gemini";
35в†’  }
36в†’
37в†’  if (
38в†’    hostname === "grok.com" ||
39в†’    hostname.endsWith(".grok.com") ||
40в†’    (hostname === "x.com" && pathname.includes("/grok"))
41в†’  ) {
42в†’    return "grok";
43в†’  }
44в†’
45в†’  if (hostname.includes("deepseek")) {
46в†’    return "deepseek";
47в†’  }
48в†’
49в†’  if (hostname.includes("notebooklm")) {
50в†’    return "notebooklm";
51в†’  }
52в†’
53в†’  return "unknown";
54в†’}
