 15в†’function serializeImport(job: ImportJob) {
 16в†’  return {
 17в†’    id: job.id,
 18в†’    sourceUrl: job.sourceUrl,
 19в†’    sourcePlatform: job.sourcePlatform,
 20в†’    mode: job.mode,
 21в†’    status: job.status,
 22в†’    currentStage: job.currentStage,
 23в†’    createdAt: job.createdAt,
 24в†’    updatedAt: job.updatedAt,
 25в†’    warningsJson: JSON.stringify(job.warnings),
 26в†’    error: job.error ?? null,
 27в†’    errorStage: job.errorStage ?? null,
 28в†’    summaryJson: job.summary ? JSON.stringify(job.summary) : null,
 29в†’    conversationJson: job.conversation
 30в†’      ? JSON.stringify(job.conversation)
 31в†’      : null,
 32в†’    artifactsJson: job.artifacts ? JSON.stringify(job.artifacts) : null,
