 47в†’    sourceUrl: row.sourceUrl,
 48в†’    sourcePlatform: row.sourcePlatform,
 49в†’    mode: row.mode,
 50в†’    status: row.status,
 51в†’    currentStage: row.currentStage,
 52в†’    createdAt: row.createdAt,
 53в†’    updatedAt: row.updatedAt,
