127в†’export function listImportSummaries(
128в†’  params?: Partial<ImportListRequest>,
129в†’): ImportSummary[] {
130в†’  const sortBy = params?.sortBy ?? "createdAt";
131в†’  const sortOrder = params?.sortOrder ?? "desc";
132в†’
133в†’  const columnMap = {
134в†’    createdAt: imports.createdAt,
135в†’    updatedAt: imports.updatedAt,
136в†’    sourcePlatform: imports.sourcePlatform,
137в†’    status: imports.status,
138в†’  } as const;
139в†’
140в†’  const orderColumn = columnMap[sortBy];
141в†’  const orderFn = sortOrder === "asc" ? asc : desc;
142в†’
143в†’  let query = db
144в†’    .select({
145в†’      id: imports.id,
146в†’      sourceUrl: imports.sourceUrl,
147в†’      sourcePlatform: imports.sourcePlatform,
148в†’      mode: imports.mode,
149в†’      status: imports.status,
150в†’      currentStage: imports.currentStage,
151в†’      createdAt: imports.createdAt,
152в†’      updatedAt: imports.updatedAt,
153в†’      warningsJson: imports.warningsJson,
154в†’      error: imports.error,
155в†’      summaryJson: imports.summaryJson,
156в†’      pageTitle: importSnapshots.pageTitle,
157в†’    })
158в†’    .from(imports)
159в†’    .leftJoin(importSnapshots, eq(imports.id, importSnapshots.importId))
160в†’    .orderBy(orderFn(orderColumn))
161в†’    .$dynamic();
162в†’
163в†’  const conditions = [];
164в†’
165в†’  if (params?.status) {
166в†’    conditions.push(eq(imports.status, params.status));
167в†’  }
168в†’
169в†’  if (params?.platform) {
170в†’    conditions.push(eq(imports.sourcePlatform, params.platform));
171в†’  }
172в†’
173в†’  if (params?.search) {
174в†’    const pattern = `%${params.search}%`;
175в†’    conditions.push(
176в†’      or(
177в†’        like(imports.sourceUrl, pattern),
178в†’        like(importSnapshots.pageTitle, pattern),
179в†’      ),
180в†’    );
181в†’  }
182в†’
183в†’  if (conditions.length > 0) {
184в†’    query = query.where(and(...conditions));
185в†’  }
186в†’
187в†’  return query.all().flatMap((row) => {
188в†’    const parsed = importSummarySchema.safeParse({
189в†’      id: row.id,
190в†’      sourceUrl: row.sourceUrl,
191в†’      sourcePlatform: row.sourcePlatform,
192в†’      mode: row.mode,
193в†’      status: row.status,
194в†’      currentStage: row.currentStage,
195в†’      createdAt: row.createdAt,
196в†’      updatedAt: row.updatedAt,
197в†’      warnings: parseJson<string[]>(row.warningsJson) ?? [],
198в†’      error: row.error ?? undefined,
199в†’      summary: parseJson<ImportJob["summary"]>(row.summaryJson),
200в†’      pageTitle: row.pageTitle ?? undefined,
201в†’    });
202в†’    return parsed.success ? [parsed.data] : [];
203в†’  });
204в†’}
