  1в†’import type { Browser, BrowserContext } from "playwright";
  2в†’import { chromium } from "playwright";
  3в†’
  4в†’import {
  5в†’  BROWSER_IDLE_SHUTDOWN_MS,
  6в†’  MAX_CONCURRENT_BROWSER_CONTEXTS,
  7в†’} from "./constants.js";
  8в†’
  9в†’export const MAX_CONTEXTS_PER_BROWSER = 50;
 10в†’
 11в†’type QueueEntry = {
 12в†’  resolve: (ctx: BrowserContext) => void;
 13в†’  reject: (err: Error) => void;
 14в†’};
 15в†’
 16в†’let browser: Browser | null = null;
 17в†’let launchPromise: Promise<Browser> | null = null;
 18в†’let activeContextCount = 0;
 19в†’let totalContextCount = 0;
 20в†’let idleTimer: ReturnType<typeof setTimeout> | null = null;
 21в†’const queue: QueueEntry[] = [];
 22в†’
 23в†’function clearIdleTimer() {
 24в†’  if (idleTimer !== null) {
 25в†’    clearTimeout(idleTimer);
 26в†’    idleTimer = null;
 27в†’  }
 28в†’}
 29в†’
 30в†’function scheduleIdleShutdown() {
 31в†’  clearIdleTimer();
 32в†’  idleTimer = setTimeout(async () => {
 33в†’    if (activeContextCount === 0 && browser !== null) {
 34в†’      const instance = browser;
 35в†’      browser = null;
 36в†’      totalContextCount = 0;
 37в†’      await instance.close();
 38в†’    }
 39в†’  }, BROWSER_IDLE_SHUTDOWN_MS);
 40в†’}
 41в†’
 42в†’async function ensureBrowser(): Promise<Browser> {
 43в†’  if (browser !== null) {
 44в†’    return browser;
 45в†’  }
 46в†’
 47в†’  if (launchPromise !== null) {
 48в†’    return launchPromise;
 49в†’  }
 50в†’
 51в†’  launchPromise = (async () => {
 52в†’    const instance = await chromium.launch({ headless: true });
 53в†’    instance.on("disconnected", () => {
 54в†’      if (browser === instance) {
 55в†’        browser = null;
 56в†’        totalContextCount = 0;
 57в†’      }
 58в†’    });
 59в†’    browser = instance;
 60в†’    launchPromise = null;
 61в†’    return instance;
 62в†’  })();
 63в†’
 64в†’  return launchPromise;
 65в†’}
 66в†’
 67в†’async function createContext(): Promise<BrowserContext> {
 68в†’  if (
 69в†’    totalContextCount >= MAX_CONTEXTS_PER_BROWSER &&
 70в†’    activeContextCount === 0 &&
 71в†’    browser !== null
 72в†’  ) {
 73в†’    const old = browser;
 74в†’    browser = null;
 75в†’    totalContextCount = 0;
 76в†’    await old.close();
 77в†’  }
 78в†’
 79в†’  const instance = await ensureBrowser();
 80в†’  clearIdleTimer();
 81в†’
 82в†’  const ctx = await instance.newContext();
 83в†’  activeContextCount++;
 84в†’  totalContextCount++;
 85в†’  return ctx;
 86в†’}
 87в†’
 88в†’export async function acquireContext(): Promise<BrowserContext> {
 89в†’  if (activeContextCount >= MAX_CONCURRENT_BROWSER_CONTEXTS) {
 90в†’    return new Promise<BrowserContext>((resolve, reject) => {
 91в†’      queue.push({ resolve, reject });
 92в†’    });
 93в†’  }
 94в†’
 95в†’  return createContext();
 96в†’}
 97в†’
 98в†’export async function releaseContext(context: BrowserContext): Promise<void> {
 99в†’  await context.close();
100в†’  activeContextCount--;
101в†’
102в†’  if (queue.length > 0) {
103в†’    const next = queue.shift()!;
104в†’    try {
105в†’      const ctx = await createContext();
106в†’      next.resolve(ctx);
107в†’    } catch (err) {
108в†’      next.reject(err instanceof Error ? err : new Error(String(err)));
109в†’    }
110в†’  } else if (activeContextCount === 0) {
111в†’    scheduleIdleShutdown();
112в†’  }
113в†’}
114в†’
115в†’export async function shutdownPool(): Promise<void> {
116в†’  clearIdleTimer();
117в†’
118в†’  while (queue.length > 0) {
119в†’    const entry = queue.shift()!;
120в†’    entry.reject(new Error("Pool shut down"));
121в†’  }
122в†’
123в†’  if (browser !== null) {
124в†’    const instance = browser;
125в†’    browser = null;
126в†’    await instance.close();
127в†’  }
128в†’
129в†’  launchPromise = null;
130в†’  activeContextCount = 0;
131в†’  totalContextCount = 0;
132в†’}
133в†’
