139в†’    }
140в†’
141в†’    withTransaction(() => {
142в†’      patchJob(id, {
143в†’        currentStage: "render",
144в†’        conversation: imported.conversation,
145в†’        summary: {
146в†’          messageCount: imported.conversation.messages.length,
147в†’          transcriptWords: conversationWordCount(imported.conversation),
148в†’        },
149в†’        warnings: imported.warnings,
150в†’      });
151в†’
152в†’      saveImportSnapshot({
153в†’        importId: id,
154в†’        sourceUrl: job.sourceUrl,
155в†’        finalUrl: imported.snapshot.finalUrl,
156в†’        fetchedAt: imported.snapshot.fetchedAt,
157в†’        pageTitle: imported.snapshot.pageTitle,
158в†’        rawHtml: imported.snapshot.rawHtml,
159в†’        normalizedPayload: imported.snapshot.normalizedPayload,
160в†’        fetchMetadata: imported.snapshot.fetchMetadata,
161в†’      });
162в†’
163в†’      const rendered = getImportJob(id);
164в†’      if (!rendered) {
165в†’        return;
166в†’      }
167в†’
168в†’      patchJob(id, {
169в†’        status: "completed",
170в†’        currentStage: "done",
171в†’        artifacts: buildArtifacts(rendered),
172в†’      });
173в†’    });
174в†’  } catch (error) {
175в†’    const currentJob = getPersistedImport(id);
176в†’    patchJob(id, {
177в†’      status: "failed",
178в†’      errorStage: currentJob?.currentStage,
179в†’      currentStage: "done",
180в†’      error:
181в†’        error instanceof Error
182в†’          ? error.message
183в†’          : "Die Import-Pipeline ist fehlgeschlagen.",
184в†’    });
185в†’  }
186в†’}
