  1в†’import type { Browser, BrowserContext } from "playwright";
  2в†’import { chromium } from "playwright";
  3в†’
  4в†’import {
  5в†’  BROWSER_IDLE_SHUTDOWN_MS,
  6в†’  MAX_CONCURRENT_BROWSER_CONTEXTS,
  7в†’} from "./constants.js";
  8в†’
  9в†’export const MAX_CONTEXTS_PER_BROWSER = 50;
 10в†’
 11в†’type QueueEntry = {
 12в†’  resolve: (ctx: BrowserContext) => void;
 13в†’  reject: (err: Error) => void;
 14в†’};
 15в†’
 16в†’let browser: Browser | null = null;
 17в†’let launchPromise: Promise<Browser> | null = null;
 18в†’let activeContextCount = 0;
 19в†’let totalContextCount = 0;
 20в†’let idleTimer: ReturnType<typeof setTimeout> | null = null;
 21в†’const queue: QueueEntry[] = [];
 22в†’
 23в†’function clearIdleTimer() {
 24в†’  if (idleTimer !== null) {
 25в†’    clearTimeout(idleTimer);
 26в†’    idleTimer = null;
 27в†’  }
 28в†’}
 29в†’
 30в†’function scheduleIdleShutdown() {
 31в†’  clearIdleTimer();
 32в†’  idleTimer = setTimeout(async () => {
 33в†’    if (activeContextCount === 0 && browser !== null) {
 34в†’      const instance = browser;
 35в†’      browser = null;
 36в†’      totalContextCount = 0;
 37в†’      await instance.close();
 38в†’    }
 39в†’  }, BROWSER_IDLE_SHUTDOWN_MS);
 40в†’}
 41в†’
 42в†’async function ensureBrowser(): Promise<Browser> {
 43в†’  if (browser !== null) {
 44в†’    return browser;
 45в†’  }
 46в†’
 47в†’  if (launchPromise !== null) {
 48в†’    return launchPromise;
 49в†’  }
 50в†’
 51в†’  launchPromise = (async () => {
 52в†’    const instance = await chromium.launch({ headless: true });
 53в†’    instance.on("disconnected", () => {
 54в†’      if (browser === instance) {
 55в†’        browser = null;
 56в†’        totalContextCount = 0;
 57в†’      }
 58в†’    });
 59в†’    browser = instance;
 60в†’    launchPromise = null;
 61в†’    return instance;
 62в†’  })();
 63в†’
 64в†’  return launchPromise;
 65в†’}
 66в†’
 67в†’async function createContext(): Promise<BrowserContext> {
 68в†’  if (
 69в†’    totalContextCount >= MAX_CONTEXTS_PER_BROWSER &&
 70в†’    activeContextCount === 0 &&
 71в†’    browser !== null
 72в†’  ) {
 73в†’    const old = browser;
 74в†’    browser = null;
 75в†’    totalContextCount = 0;
 76в†’    await old.close();
 77в†’  }
 78в†’
 79в†’  const instance = await ensureBrowser();
 80в†’  clearIdleTimer();
