  15в†’
  16в†’/** Timeout for waiting for Google consent buttons to appear. */
  17в†’export const GOOGLE_CONSENT_BUTTON_TIMEOUT_MS = 10_000;
  18в†’
  19в†’/** Navigation timeout for Google-platform pages (Gemini, NotebookLM). */
