 147в†’async function maybeDismissGoogleConsentGate(page: Page) {
 148в†’  if (!isGoogleConsentUrl(page.url())) {
 149в†’    return false;
 150в†’  }
 151в†’
 152в†’  await page
 153в†’    .waitForSelector('button[jsname="tWT92d"], button[jsname="b3VHJd"]', {
 154в†’      state: "visible",
 155в†’      timeout: GOOGLE_CONSENT_BUTTON_TIMEOUT_MS,
 156в†’    })
 157в†’    .catch(() => undefined);
 158в†’
 159в†’  const rejectAllButton = page.locator('button[jsname="tWT92d"]').first();
 160в†’  const acceptAllButton = page.locator('button[jsname="b3VHJd"]').first();
 161в†’
 162в†’  let actionButton = rejectAllButton;
 163в†’
 164в†’  if (!(await actionButton.isVisible().catch(() => false))) {
