 180в†’      await page
 181в†’        .waitForLoadState("domcontentloaded", {
 182в†’          timeout: GOOGLE_CONSENT_REDIRECT_TIMEOUT_MS,
 183в†’        })
 184в†’        .catch(() => undefined);
 185в†’      return true;
 186в†’    }
 187в†’
 188в†’    await page.waitForTimeout(GOOGLE_CONSENT_POLLING_INTERVAL_MS);
 189в†’  }
 190в†’
 191в†’  return !isGoogleConsentUrl(page.url());
 192в†’}
