 194в†’export async function importGenericSharePage(
 195в†’  url: string,
 196в†’  options: {
 197в†’    onStage?: StageCallback;
 198в†’    sourcePlatform: SourcePlatform;
 199в†’  },
 200в†’) {
 201в†’  const context = await acquireContext();
 202в†’
 203в†’  try {
 204в†’    if (!isGoogleSourcePlatform(options.sourcePlatform)) {
 205в†’      await context.route("**/*", (route) => {
 206в†’        const resourceType = route.request().resourceType();
 207в†’
 208в†’        if (
 209в†’          resourceType === "image" ||
 210в†’          resourceType === "media" ||
 211в†’          resourceType === "font"
 212в†’        ) {
