 235в†’      .waitForLoadState("domcontentloaded", {
 236в†’        timeout: DOM_CONTENT_LOADED_TIMEOUT_MS,
 237в†’      })
 238в†’      .catch(() => undefined);
 239в†’
 240в†’    if (isGoogleSourcePlatform(options.sourcePlatform)) {
 241в†’      await maybeDismissGoogleConsentGate(page);
 242в†’    }
 243в†’
 244в†’    if (isGoogleConsentUrl(page.url())) {
