 247в†’      );
 248в†’    }
 249в†’
 250в†’    await page
 251в†’      .waitForFunction(
 252в†’        () => {
 253в†’          const root =
 254в†’            document.querySelector("main, [role='main'], article, body") ??
 255в†’            document.body;
 256в†’          return (root.textContent ?? "").trim().length > 32;
 257в†’        },
 258в†’        {
 259в†’          timeout: FUNCTION_WAIT_TIMEOUT_MS,
 260в†’        },
 261в†’      )
 262в†’      .catch(() => undefined);
 263в†’
 264в†’    await page
 265в†’      .waitForLoadState("networkidle", {
 266в†’        timeout: NETWORK_IDLE_TIMEOUT_MS,
 267в†’      })
 268в†’      .catch(() => undefined);
 269в†’    await page.waitForTimeout(PAGE_STABILIZATION_DELAY_MS);
 270в†’
 271в†’    options.onStage?.("extract");
 272в†’    const extractionConfig = {
 273в†’      MIN_CONTENT_TEXT_LENGTH,
 274в†’      MIN_MEANINGFUL_CHILDREN,
 275в†’      MIN_CHILD_TEXT_LENGTH,
 276в†’      MIN_TEXT_LENGTH_FOR_MEANINGFUL_CHILDREN,
 277в†’      MAX_SAMPLE_CHILDREN,
 278в†’      MAX_TEXT_LENGTH_FOR_AVERAGING,
 279в†’      MAX_CONTAINER_CANDIDATES,
 280в†’      SCORE_CHILDREN_WEIGHT,
 281в†’      SCORE_TAG_RATIO_WEIGHT,
 282в†’      SCORE_HINTED_WEIGHT,
 283в†’      SCORE_BLOCK_WEIGHT,
 284в†’      SCORE_ACTION_WEIGHT,
 285в†’      SCORE_AVG_TEXT_DIVISOR,
 286в†’      SCORE_AVG_TEXT_MAX,
 287в†’      SCORE_DEPTH_PENALTY,
 288в†’      SCORE_FORM_PENALTY,
 289в†’      CANDIDATE_DEDUP_THRESHOLD,
 290в†’      MIN_CONTAINER_SCORE_THRESHOLD,
 291в†’      MIN_FALLBACK_TEXT_LENGTH,
 292в†’      MAX_FALLBACK_TEXT_LENGTH,
 293в†’      MAX_FALLBACK_CANDIDATES,
 294в†’      MAX_HINT_DEPTH,
 295в†’      MAX_HINT_CLASSES,
 296в†’    };
 297в†’    const extracted = await page.evaluate(
 298в†’      ({ platform, cfg }) => {
 299в†’        const wrapperTags = new Set([
 300в†’          "ARTICLE",
 301в†’          "SECTION",
 302в†’          "DIV",
 303в†’          "SPAN",
 304в†’          "FIGURE",
 305в†’          "MAIN",
 306в†’        ]);
 307в†’        const blockTags = new Set([
 308в†’          "P",
 309в†’          "H1",
 310в†’          "H2",
 311в†’          "H3",
 312в†’          "H4",
 313в†’          "H5",
 314в†’          "H6",
 315в†’          "UL",
 316в†’          "OL",
 317в†’          "PRE",
 318в†’          "BLOCKQUOTE",
 319в†’          "TABLE",
 320в†’          "HR",
 321в†’        ]);
 322в†’        const codeLanguageLabels = new Set([
