 426в†’            (child) => child.tagName === "LI",
 427в†’          );
 428в†’
 429в†’          for (const listItem of listItems) {
 430в†’            let ownText = "";
 431в†’
 432в†’            for (const childNode of Array.from(listItem.childNodes)) {
 433в†’              if (
 434в†’                childNode.nodeType === Node.ELEMENT_NODE &&
 435в†’                ["UL", "OL"].includes((childNode as Element).tagName)
