import { describe, expect, test } from "vitest";
import { DOM_KIT_SCRIPT } from "./parser-dom-kit";
import type { DomKit } from "./parser-dom-kit";

describe("parser-dom-kit", () => {
  describe("DOM_KIT_SCRIPT", () => {
    test("is a non-empty string", () => {
      expect(typeof DOM_KIT_SCRIPT).toBe("string");
      expect(DOM_KIT_SCRIPT.length).toBeGreaterThan(0);
    });

    test("starts with an IIFE", () => {
      expect(DOM_KIT_SCRIPT.trimStart()).toMatch(/^\(function\(\)/);
    });

    test("ends the IIFE with invocation and semicolon", () => {
      expect(DOM_KIT_SCRIPT.trimEnd()).toMatch(/\}\)\(\);$/);
    });
  });

  describe("contains all expected function names", () => {
    test.each([
      "normalizeWhitespace",
      "inlineText",
      "inlineFromElement",
      "extractListItems",
      "detectCodeLanguage",
      "extractCodeText",
      "extractTable",
      "elementToBlocks",
    ])("contains function %s", (fnName) => {
      expect(DOM_KIT_SCRIPT).toContain(`function ${fnName}`);
    });
  });

  describe("contains all expected tag sets", () => {
    test.each(["wrapperTags", "blockTags", "codeLanguageLabels"])(
      "contains tag set %s",
      (setName) => {
        expect(DOM_KIT_SCRIPT).toContain(setName);
      },
    );
  });

  describe("exposes all helpers on globalThis.__domKit", () => {
    test("assigns to globalThis.__domKit", () => {
      expect(DOM_KIT_SCRIPT).toContain("globalThis.__domKit");
    });

    test.each([
      "wrapperTags",
      "blockTags",
      "codeLanguageLabels",
      "normalizeWhitespace",
      "inlineText",
      "inlineFromElement",
      "extractListItems",
      "detectCodeLanguage",
      "extractCodeText",
      "extractTable",
      "elementToBlocks",
    ])("exports %s on __domKit", (name) => {
      // The assignment object should contain each name
      const assignmentPattern = new RegExp(
        `globalThis\\.__domKit\\s*=\\s*\\{[^}]*${name}`,
      );
      expect(DOM_KIT_SCRIPT).toMatch(assignmentPattern);
    });
  });

  describe("DomKit interface", () => {
    test("is importable as a type", () => {
      // Type-level check: if this compiles, the interface is exported
      const _typeCheck: DomKit | undefined = undefined;
      expect(_typeCheck).toBeUndefined();
    });
  });

  describe("string escaping correctness", () => {
    test("regex unicode escape is double-escaped for string context", () => {
      // In the string, \\u00a0 should appear (not the actual nbsp character)
      expect(DOM_KIT_SCRIPT).toContain("\\u00a0");
    });

    test("regex character classes are properly escaped", () => {
      // Should contain \\t, \\f, \\v for whitespace character class
      expect(DOM_KIT_SCRIPT).toContain("\\t");
      expect(DOM_KIT_SCRIPT).toContain("\\f");
      expect(DOM_KIT_SCRIPT).toContain("\\v");
    });

    test("newline literals in regex are escaped", () => {
      // The regex /\\n{3,}/ should appear as \\n in the string
      expect(DOM_KIT_SCRIPT).toContain("\\n");
    });
  });

  describe("script is valid JavaScript", () => {
    test("can be parsed without syntax errors", () => {
      // new Function() parses the script вЂ” throws SyntaxError if invalid JS
      expect(() => new Function(DOM_KIT_SCRIPT)).not.toThrow();
    });
  });
});

import type {
  Conversation,
  ImportStage,
  NormalizedSnapshotPayload,
} from "@chat-exporter/shared";

/** Callback for reporting import stage progress. */
export type StageCallback = (
  stage: Extract<ImportStage, "fetch" | "extract" | "normalize" | "structure">,
) => void;

/** Standardized result returned by every platform parser. */
export type PlatformParserResult = {
  conversation: Conversation;
  warnings: string[];
  snapshot: {
    finalUrl: string;
    fetchedAt: string;
    pageTitle: string;
    rawHtml: string;
    normalizedPayload: NormalizedSnapshotPayload;
    fetchMetadata: {
      articleCount: number;
      messageCount: number;
      rawHtmlBytes: number;
    };
  };
};

/** Signature that every platform-specific parser function must implement. */
export type PlatformParser = (
  url: string,
  options?: { onStage?: StageCallback },
) => Promise<PlatformParserResult>;

