import { describe, expect, test } from "vitest";
import { DOM_KIT_SCRIPT } from "./parser-dom-kit";
import type { DomKit } from "./parser-dom-kit";

describe("parser-dom-kit", () => {
  describe("DOM_KIT_SCRIPT", () => {
    test("is a non-empty string", () => {
      expect(typeof DOM_KIT_SCRIPT).toBe("string");
      expect(DOM_KIT_SCRIPT.length).toBeGreaterThan(0);
    });

    test("starts with an IIFE", () => {
      expect(DOM_KIT_SCRIPT.trimStart()).toMatch(/^\(function\(\)/);
    });

    test("ends the IIFE with invocation and semicolon", () => {
      expect(DOM_KIT_SCRIPT.trimEnd()).toMatch(/\}\)\(\);$/);
    });
  });

  describe("contains all expected function names", () => {
    test.each([
      "normalizeWhitespace",
      "inlineText",
      "inlineFromElement",
      "extractListItems",
      "detectCodeLanguage",
      "extractCodeText",
      "extractTable",
      "elementToBlocks",
    ])("contains function %s", (fnName) => {
      expect(DOM_KIT_SCRIPT).toContain(`function ${fnName}`);
    });
  });

  describe("contains all expected tag sets", () => {
    test.each(["wrapperTags", "blockTags", "codeLanguageLabels"])(
      "contains tag set %s",
      (setName) => {
        expect(DOM_KIT_SCRIPT).toContain(setName);
      },
    );
  });

  describe("exposes all helpers on globalThis.__domKit", () => {
    test("assigns to globalThis.__domKit", () => {
      expect(DOM_KIT_SCRIPT).toContain("globalThis.__domKit");
    });

    test.each([
      "wrapperTags",
      "blockTags",
      "codeLanguageLabels",
      "normalizeWhitespace",
      "inlineText",
      "inlineFromElement",
      "extractListItems",
      "detectCodeLanguage",
      "extractCodeText",
      "extractTable",
      "elementToBlocks",
    ])("exports %s on __domKit", (name) => {
      const assignmentPattern = new RegExp(
        `globalThis\\.__domKit\\s*=\\s*\\{[^}]*${name}`,
      );
      expect(DOM_KIT_SCRIPT).toMatch(assignmentPattern);
    });
  });

  describe("DomKit interface", () => {
    test("is importable as a type", () => {
      // Type-level check: if this compiles, the interface is exported
      const _typeCheck: DomKit | undefined = undefined;
      expect(_typeCheck).toBeUndefined();
    });
  });

  describe("string escaping correctness", () => {
    test("regex unicode escape is double-escaped for string context", () => {
      expect(DOM_KIT_SCRIPT).toContain("\\u00a0");
    });

    test("regex character classes are properly escaped", () => {
      expect(DOM_KIT_SCRIPT).toContain("\\t");
      expect(DOM_KIT_SCRIPT).toContain("\\f");
      expect(DOM_KIT_SCRIPT).toContain("\\v");
    });

    test("newline literals in regex are escaped", () => {
      expect(DOM_KIT_SCRIPT).toContain("\\n");
    });
  });

  describe("script is valid JavaScript", () => {
    test("can be parsed by Function constructor without syntax errors", () => {
      // This validates the string is syntactically valid JavaScript.
      // The Function constructor parses but does not execute the code here.
      // biome-ignore lint/security/noGlobalEval: test-only validation of generated JS string
      expect(() => new Function(DOM_KIT_SCRIPT)).not.toThrow();
    });
  });
});

import { describe, expect, test } from "vitest";

import { classifySourcePlatform } from "./source-platform.js";

describe("classifySourcePlatform", () => {
  describe("existing platforms", () => {
    test.each([
      ["https://chatgpt.com/share/abc", "chatgpt"],
      ["https://chat.openai.com/share/abc", "chatgpt"],
      ["https://claude.ai/chat/abc", "claude"],
      ["https://gemini.google.com/share/abc", "gemini"],
      ["https://grok.com/share/abc", "grok"],
      ["https://chat.deepseek.com/share/abc", "deepseek"],
      ["https://notebooklm.google.com/share/abc", "notebooklm"],
    ])("classifies %s as %s", (url, expected) => {
      expect(classifySourcePlatform(url)).toBe(expected);
    });
  });

  describe("new platforms", () => {
    test("classifies aistudio.google.com as aistudio", () => {
      const result = classifySourcePlatform(
        "https://aistudio.google.com/app/prompts",
      );

      expect(result).toBe("aistudio");
    });

    test("classifies subdomain of aistudio.google.com as aistudio", () => {
      const result = classifySourcePlatform(
        "https://sub.aistudio.google.com/app/prompts",
      );

      expect(result).toBe("aistudio");
    });

    test("classifies www.perplexity.ai as perplexity", () => {
      const result = classifySourcePlatform(
        "https://www.perplexity.ai/search/abc",
      );

      expect(result).toBe("perplexity");
    });

    test("classifies perplexity.ai as perplexity", () => {
      const result = classifySourcePlatform("https://perplexity.ai/search/abc");

      expect(result).toBe("perplexity");
    });

    test("classifies chat.mistral.ai as lechat", () => {
      const result = classifySourcePlatform(
        "https://chat.mistral.ai/chat/abc",
      );

      expect(result).toBe("lechat");
    });

    test("classifies subdomain of mistral.ai as lechat", () => {
      const result = classifySourcePlatform(
        "https://api.mistral.ai/v1/chat",
      );

      expect(result).toBe("lechat");
    });

    test("classifies kimi.moonshot.cn as kimi", () => {
      const result = classifySourcePlatform(
        "https://kimi.moonshot.cn/share/abc",
      );

      expect(result).toBe("kimi");
    });

    test("classifies subdomain of moonshot.cn as kimi", () => {
      const result = classifySourcePlatform(
        "https://sub.moonshot.cn/share/abc",
      );

      expect(result).toBe("kimi");
    });
  });

  test("returns unknown for unrecognized URLs", () => {
    const result = classifySourcePlatform("https://example.com/chat");

    expect(result).toBe("unknown");
  });
});

